exports.sendBulkEmail = async (req, res) => {
  try {
    if (req.method !== 'POST') {
      return res.status(405).json({ error: 'Method not allowed' });
    }

    const { emails } = req.body;

    if (!emails || !Array.isArray(emails)) {
      return res.status(400).json({ error: 'Missing or invalid emails array' });
    }

    const messages = emails.map(emailData => {
      const msg = {
        to: emailData.to,
        from: emailData.from,
        subject: emailData.subject
      };

      if (emailData.text) msg.text = emailData.text;
      if (emailData.html) msg.html = emailData.html;
      if (emailData.templateId) {
        msg.templateId = emailData.templateId;
        if (emailData.dynamicTemplateData) {
          msg.dynamicTemplateData = emailData.dynamicTemplateData;
        }
      }

      return msg;
    });

    const response = await sgMail.send(messages);

    return res.status(200).json({
      success: true,
      message: 'Bulk emails sent successfully',
      count: messages.length,
      data: response
    });

  } catch (error) {
    console.error('Error sending bulk email:', error);
    return res.status(500).json({
      success: false,
      error: error.message,
      details: error.response ? error.response.body : null
    });
  }
};

exports.sendBulkSMS = async (req, res) => {
  try {
    if (req.method !== 'POST') {
      return res.status(405).json({ error: 'Method not allowed' });
    }

    const { messages } = req.body;

    if (!messages || !Array.isArray(messages)) {
      return res.status(400).json({ error: 'Missing or invalid messages array' });
    }

    const results = [];
    const errors = [];

    for (const smsData of messages) {
      try {
        const result = await sendSMS(smsData);
        results.push(result);
      } catch (error) {
        errors.push({
          to: smsData.to,
          error: error.message
        });
      }
    }

    return res.status(200).json({
      success: true,
      message: 'Bulk SMS processing completed',
      sent: results.length,
      failed: errors.length,
      results,
      errors
    });

  } catch (error) {
    console.error('Error sending bulk SMS:', error);
    return res.status(500).json({
      success: false,
      error: error.message
    });
  }
};

exports.healthCheck = async (req, res) => {
  const health = {
    status: 'healthy',
    timestamp: new Date().toISOString(),
    services: {}
  };

  try {
    health.services.sendgrid = SENDGRID_API_KEY ? 'configured' : 'missing';
    health.services.twilio = (TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN) ? 'configured' : 'missing';
    
    return res.status(200).json(health);
  } catch (error) {
    health.status = 'unhealthy';
    health.error = error.message;
    return res.status(500).json(health);
  }
};